// // This SR flip-flop is designed to reset on the rising edge of the clock when S is high and R is low.
module sr_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    output reg Q
);
    always @(posedge clk) begin
        if (S && !R) 
            Q <= 1; // Set
        else if (!S && R) 
            Q <= 0; // Reset
        // If S and R are both 0, Q remains unchanged
    end
endmodule
